export function checkerFunctionRegistryByName(): ReadonlyMap<string, readonly CheckerFunctionRegistryEntry[]> {
  const byName = new Map<string, CheckerFunctionRegistryEntry[]>();
  for (const entry of checkerFunctionRegistry) {
    const existing = byName.get(entry.name) ?? [];
    existing.push(entry);
    byName.set(entry.name, existing);
  }
  return byName;
}

export function checkerFunctionRegistryByFile(): ReadonlyMap<string, readonly CheckerFunctionRegistryEntry[]> {
  const byFile = new Map<string, CheckerFunctionRegistryEntry[]>();
  for (const entry of checkerFunctionRegistry) {
    const existing = byFile.get(entry.upstreamFile) ?? [];
    existing.push(entry);
    byFile.set(entry.upstreamFile, existing);
  }
  return byFile;
}

export function checkerFunctionRegistrySummary(): ReadonlyMap<string, number> {
  const summary = new Map<string, number>();
  for (const entry of checkerFunctionRegistry) summary.set(entry.category, (summary.get(entry.category) ?? 0) + 1);
  return summary;
}

